@app.get("/reset-mfa/confirm")
def reset_mfa_confirm():
    token = (request.args.get("token") or "").strip()
    if not token:
        return jsonify({"error": "token required"}), 400

    th = hash_token(token)
    conn = db()
    try:
        row = conn.execute(
            "SELECT * FROM mfa_reset_tokens WHERE token_hash = ?",
            (th,),
        ).fetchone()
        if not row:
            return jsonify({"error": "invalid token"}), 400

        if row["used_at"]:
            return jsonify({"error": "token already used"}), 400

        expires_at = datetime.fromisoformat(row["expires_at"].replace("Z", ""))
        if now_utc() > expires_at:
            return jsonify({"error": "token expired"}), 400

        user_id = int(row["user_id"])

        conn.execute(
            "UPDATE users SET mfa_enabled = 0, mfa_secret = NULL, mfa_recovery_codes_hash = NULL WHERE id = ?",
            (user_id,),
        )
        conn.execute(
            "UPDATE mfa_reset_tokens SET used_at = ? WHERE id = ?",
            (now_utc().isoformat() + "Z", int(row["id"])),
        )
        conn.commit()

        clear_auth_session()
        return jsonify({"ok": True, "message": "MFA reset. You can now log in with password only."}), 200
    finally:
        conn.close()


